import{_ as a,o as r,c as i,a2 as t}from"./chunks/framework.B36PHH5O.js";const p=JSON.parse('{"title":"S3 For XunRuiCMS について","description":"","frontmatter":{},"headers":[],"relativePath":"ja/about.md","filePath":"ja/about.md","lastUpdated":1778063279000}'),l={name:"ja/about.md"};function o(n,e,h,s,u,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="s3-for-xunruicms-について" tabindex="-1">S3 For XunRuiCMS について <a class="header-anchor" href="#s3-for-xunruicms-について" aria-label="Permalink to &quot;S3 For XunRuiCMS について&quot;">​</a></h1><h2 id="プロジェクト概要" tabindex="-1">プロジェクト概要 <a class="header-anchor" href="#プロジェクト概要" aria-label="Permalink to &quot;プロジェクト概要&quot;">​</a></h2><p>S3 For XunRuiCMS は AWS S3 によるクラウドストレージを XunRuiCMS プロジェクトに提供するプラグインです。</p><h2 id="機能" tabindex="-1">機能 <a class="header-anchor" href="#機能" aria-label="Permalink to &quot;機能&quot;">​</a></h2><ul><li>一貫したファイルアップロード/ダウンロード管理機能</li><li>大容量ファイルの分割アップロードと中断からの再開支援</li><li>XunRuiCMS ファイル管理システムとシームレスな統合</li><li>完璧なエラーハンドリングとログ記録</li></ul><h2 id="インストール要件" tabindex="-1">インストール要件 <a class="header-anchor" href="#インストール要件" aria-label="Permalink to &quot;インストール要件&quot;">​</a></h2><ul><li><p>PHP 7.4 以上</p></li><li><p>XunRuiCMS 5.0 以上</p></li></ul><h2 id="インストール方法" tabindex="-1">インストール方法 <a class="header-anchor" href="#インストール方法" aria-label="Permalink to &quot;インストール方法&quot;">​</a></h2><hr><p>迅睿CMSプラグイン市場からインストールしてください</p><h2 id="使用手順" tabindex="-1">使用手順 <a class="header-anchor" href="#使用手順" aria-label="Permalink to &quot;使用手順&quot;">​</a></h2><ol><li>プラグインをインストールし、迅睿CMSのバックエンドでAWS S3に関する情報を設定します</li><li>プラグインを有効にすると、迅睿CMSのファイル管理でAWS S3を使用してストレージを管理できます</li></ol><h2 id="ドキュメントサイトの技術スタック" tabindex="-1">ドキュメントサイトの技術スタック <a class="header-anchor" href="#ドキュメントサイトの技術スタック" aria-label="Permalink to &quot;ドキュメントサイトの技術スタック&quot;">​</a></h2><p>このドキュメントサイトは以下の技術で構築されています：</p><p><strong>VitePress</strong> - 静的サイト生成器、バージョン ^1.0.0</p><ul><li>官网：<a href="https://vitepress.dev/" target="_blank" rel="noreferrer">https://vitepress.dev/</a></li><li>使用ライセンス：MIT License</li></ul><p><strong>vitepress-plugin-image-viewer</strong> - ピクチャービューアー用プラグイン、バージョン ^1.1.6</p><ul><li>官网：<a href="https://github.com/noonnightrocker/vitepress-plugin-image-viewer" target="_blank" rel="noreferrer">https://github.com/noonnightrocker/vitepress-plugin-image-viewer</a></li><li>使用ライセンス：MIT License</li></ul><h2 id="応援感谢" tabindex="-1">応援感谢 <a class="header-anchor" href="#応援感谢" aria-label="Permalink to &quot;応援感谢&quot;">​</a></h2><p>Vine.js、Vite、VitePressなどのオープンソースプロジェクトの貢献者に感謝します。</p><h2 id="作者情報" tabindex="-1">作者情報 <a class="header-anchor" href="#作者情報" aria-label="Permalink to &quot;作者情報&quot;">​</a></h2><ul><li>作者：陳延德</li><li>邮箱：<a href="mailto:me@chenyande.com" target="_blank" rel="noreferrer">me@chenyande.com</a></li><li>站点：<a href="https://www.chenyande.com" target="_blank" rel="noreferrer">chenyande.com</a></li></ul><h2 id="ライセンス" tabindex="-1">ライセンス <a class="header-anchor" href="#ライセンス" aria-label="Permalink to &quot;ライセンス&quot;">​</a></h2><p>このプロジェクトはApache License 2.0に沿って公開されています。</p>',24)])])}const m=a(l,[["render",o]]);export{p as __pageData,m as default};
